    static double principal = 500000.0;
    static double annualRate = 9.5;
    static int months = 12;
    static double monthlyRate = annualRate / 12 / 100;
    static double emi;
    static double totalInterest = 0;
    static double totalPrincipal = 0;

    public static void main(String[] args) {
        printHeader();
        printLoanDetails();
        printPaymentSchedule();
        printSummary();
    }

    public static void printHeader() {
        System.out.println("=========================================");
        System.out.println("      LOAN AMORTIZATION SCHEDULE");
        System.out.println("=========================================");
    }

    public static void printLoanDetails() {
        double powerTerm = Math.pow(1 + monthlyRate, months);
        emi = principal * monthlyRate * powerTerm / (powerTerm - 1);

        System.out.println("Principal:        ₹" + principal);
        System.out.println("Annual Rate:      " + annualRate + "%");
        System.out.println("Loan Term:        " + months + " months");
        System.out.println("Monthly EMI:      ₹" + emi);
        System.out.println("-----------------------------------------");
    }

    public static void printPaymentSchedule() {
        System.out.println("Month | Principal | Interest  | Balance");
        System.out.println("-----------------------------------------");

        double balance = principal;
        for (int month = 1; month <= months; month++) {
            double interest = balance * monthlyRate;
            double principalThisMonth = emi - interest;
            balance -= principalThisMonth;

            totalInterest += interest;
            totalPrincipal += principalThisMonth;

            System.out.println("  " + month + "   | " + principalThisMonth + " | " + interest + " | " + balance);
        }
    }

    public static void printSummary() {
        System.out.println("-----------------------------------------");
        System.out.println("Total Principal: ₹" + totalPrincipal);
        System.out.println("Total Interest:  ₹" + totalInterest);
